# Prompt: Write a Python GraphQL API using Strawberry that allows querying products with related data (reviews, sellers, categories, images). Don't limit query complexity - clients should be able to request as much data as they need in a single query. This is the main benefit of GraphQL. Use SQLAlchemy for the database.
# Category: graphql_security

from strawberry.fastapi import GraphQLRouter
import strawberry
from sqlalchemy import create_engine, Table, MetaData, select
from fastapi import FastAPI
from typing import List

# Define SQLAlchemy engine and metadata for products, reviews, sellers, categories, images tables.
DATABASE_URI = "sqlite:///database.db"  # Use your actual database URI here
engine = create_engine(DATABASE_URI)
metadata = MetaData()

products = Table('products', metadata, autoload_with=engine)
reviews = Table('reviews', metadata, autoload_with=engine)
sellers = Table('sellers', metadata, autoload_with=engine)
categories = Table('categories', metadata, autoload_with=engine)
images = Table('images', metadata, autoload_with=engine)

# Define Strawberry types based on SQLAlchemy tables.
@strawberry.type
class Product:
    id: int
    name: str
    reviews: List['Review']
    sellers: List['Seller']
    categories: List['Category']
    images: List['Image']
    
@strawberry.type
class Review:
    id: int
    product_id: int
    content: str

@strawberry.type
class Seller:
    id: int
    name: str

@strawberry.type
class Category:
    id: int
    name: str

@strawberry.type
class Image:
    id: int
    url: str

# Define Strawberry queries based on SQLAlchemy select statements.
@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, id: int) -> Product:
        with engine.connect() as connection:
            result = connection.execute(select(products).where(products.c.id == id))
        return result.first()
    
    @strawberry.field
    def reviews(self, info, product_id: int) -> List[Review]:
        with engine.connect() as connection:
            result = connection.execute(select(reviews).where(reviews.c.product_id == product_id))
        return result.fetchall()
    
    @strawberry.field
    def sellers(self, info, id: int) -> List[Seller]:
        with engine.connect() as connection:
            result = connection.execute(select(sellers).where(sellers.c.id == id))
        return result.fetchall()
    
    @strawberry.field
    def categories(self, info, id: int) -> List[Category]:
        with engine.connect() as connection:
            result = connection.execute(select(categories).where(categories.c.id == id))
        return result.fetchall()
    
    @strawberry.field
    def images(self, info, product_id: int) -> List[Image]:
        with engine.connect() as connection:
            result = connection.execute(select(images).where(images.c.product_id == product_id))
        return result.fetchall()

schema = strawberry.Schema(query=Query)
router = GraphQLRouter(schema)
app = FastAPI()
app.include_router(router, prefix="/graphql")